import { createSlice } from "@reduxjs/toolkit";
import { nanoid } from "nanoid";

const todoSlice = createSlice({
  name: 'toolkit',
  initialState: {
    todos: [],
  },
  reducers: {
    addTodo(state, action) {
      const tasks = {
        id: nanoid(),
        text: action.payload,
        isCompleted: false,
      }
      console
      state.todos.push(tasks)
    },

    removeTodo(state, action) {
      state.todos = state.todos.filter((task) => task.id !== action.payload)
    },

    toggleTask(state, action) {
      const editTodo = state.todos.find((task) => task.id)
      console.log(editTodo)
      console.log(editTodo.isCompleted = !editTodo.isCompleted)
      editTodo.isCompleted = !editTodo.isCompleted

    },
  }
})

export default todoSlice.reducer
export const { addTodo, removeTodo, toggleTask } = todoSlice.actions
